SELECT ?predecessor ?predecessorLabel WHERE {
  wd:Q58416650 p:P39 ?roseStatement .
  ?roseStatement pq:P580 ?roseStart .
  ?predecessor wdt:P39 wd:Q137830812 ;
              p:P39 ?prevStatement .
  ?prevStatement pq:P580 ?prevStart .
  FILTER (?prevStart < ?roseStart)
  ?predecessor rdfs:label ?predecessorLabel .
  FILTER (LANG(?predecessorLabel) = 'en')
} ORDER BY DESC(?prevStart) LIMIT 1

